// Unifica cuerpo: n8n a veces entrega el JSON en .body y otras en la raíz.
const item = $input.first().json;
const body = item.body;
const payload =
  body !== undefined && body !== null && typeof body === 'object' && !Array.isArray(body)
    ? { ...body }
    : { ...item };
return [{ json: payload }];

const j = $input.first().json;
const msg = String(j.mensaje || '').trim();
const intent = String(j.intent || '');
const nombre = String(j.nombre || '');
const tel = String(j.telefono || '');
const email = String(j.email || '');
const prompt =
  'Eres asistente de Casetodo Carlos Ruiz (venta y alquiler de casetones). ' +
  'Devuelve SOLO texto plano en español, sin markdown ni JSON.\n\n' +
  'Tarea: ordena y clarifica el requerimiento para el equipo comercial. ' +
  'Usa secciones breves (puedes usar líneas que empiecen con guión o títulos en una sola línea). ' +
  'Incluye: tipo de solicitud, datos de contacto, detalle del pedido (cantidades, ciudad, fechas, tipo de casetón si aplica). ' +
  'Al final, si falta información, añade una línea "Pendiente:" con lo que falte.\n\n' +
  'Datos del formulario web:\n' +
  '- Tipo (intent): ' + (intent || '—') + '\n' +
  '- Nombre: ' + (nombre || '—') + '\n' +
  '- Teléfono: ' + (tel || '—') + '\n' +
  '- Correo: ' + (email || '—') + '\n\n' +
  'Mensaje del cliente:\n' +
  (msg || '(El cliente no escribió detalle.)') + '\n\n' +
  'Redacta la versión ordenada para el equipo.';
return [{ json: { ...j, _geminiPrompt: prompt } }];

const orig = $('Preparar prompt Gemini').first().json;
const gem = $input.first().json;
let text = '';
const parts = gem.content && gem.content.parts;
if (Array.isArray(parts)) {
  text = parts
    .map((p) => (p && typeof p.text === 'string' ? p.text : ''))
    .join('')
    .trim();
}
if (!text && typeof gem.mergedResponse === 'string') {
  text = gem.mergedResponse.trim();
}
if (!text && gem.candidates && gem.candidates[0] && gem.candidates[0].content) {
  const p2 = gem.candidates[0].content.parts;
  if (Array.isArray(p2)) {
    text = p2
      .map((p) => (p && typeof p.text === 'string' ? p.text : ''))
      .join('')
      .trim();
  }
}
return [
  {
    json: {
      ...orig,
      structuredMensaje: text || '(No hubo texto en la respuesta de Gemini.)'
    }
  }
];

// Datos finales + texto de ejemplo para el front (no envía correos).
const j = $input.first().json;
const nombre = String(j.nombre || 'Cliente').trim();
const email = String(j.email || '').trim();
const hasEmail = email.length > 0 && email.includes('@');
const fragment = String(j.structuredMensaje || j.mensajeOriginal || '')
  .trim()
  .slice(0, 280);
const clientMessage = hasEmail
  ? `[Prueba] Recibimos tu solicitud. En producción enviaríamos un correo de confirmación a ${email}.`
  : '[Prueba] Recibimos tu solicitud. Sin correo no habría email de confirmación al cliente.';
return [
  {
    json: {
      ...j,
      _testClientMessage: clientMessage,
      _testPreview: {
        nombre: nombre || '—',
        email: hasEmail ? email : null,
        resumenCorto: fragment || '(sin texto)'
      }
    }
  }
];
